// Parent class (superclass)
class Animal {
    String name;
    int age;

    Animal(String name, int age) {
        this.name = name;
        this.age = age;
    }

    void eat() {
        System.out.println(name + " is eating.");
    }

    void sleep() {
        System.out.println(name + " is sleeping.");
    }
}

// Child class (subclass) - inherits from Animal
class Dog extends Animal {
    String breed;

    Dog(String name, int age, String breed) {
        super(name, age);  // Call parent constructor
        this.breed = breed;
    }

    void bark() {
        System.out.println(name + " says: Woof! Woof!");
    }
}

// Another subclass
class Cat extends Animal {
    Cat(String name, int age) {
        super(name, age);
    }

    void meow() {
        System.out.println(name + " says: Meow~");
    }
}

public class InheritanceExample {
    public static void main(String[] args) {
        Dog dog = new Dog("Rex", 3, "German Shepherd");
        Cat cat = new Cat("Whiskers", 2);

        // Dog has access to Animal methods
        dog.eat();
        dog.sleep();
        dog.bark();

        System.out.println("---");

        // Cat has access to Animal methods
        cat.eat();
        cat.sleep();
        cat.meow();

        // IS-A relationship
        System.out.println("Dog is an Animal? " + (dog instanceof Animal));
        System.out.println("Cat is an Animal? " + (cat instanceof Animal));
    }
}

