phase3.solution:
class Vehicle {
    String brand;
    int speed;

    Vehicle(String brand, int speed) {
        this.brand = brand;
        this.speed = speed;
    }

    void accelerate() {
        System.out.println(brand + " is accelerating!");
    }
}

class Car extends Vehicle {
    String model;

    Car(String brand, int speed, String model) {
        super(brand, speed);
        this.model = model;
    }

    void honk() {
        System.out.println(brand + " " + model + " says: Beep beep!");
    }
}

public class Main {
    public static void main(String[] args) {
        Car car = new Car("Toyota", 120, "Camry");
        car.accelerate();
        car.honk();
    }
}
